}

glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uTime;
uniform float uSeed;
uniform float uWashScale;
uniform float uGrain;
uniform float uTerritorySoftness;
uniform float uCyanWeight;
uniform float uVioletWeight;
float hash(vec2 p){return fract(sin(dot(p,vec2(127.1,311.7))+uSeed*19.17)*43758.5453);}
float noise(vec2 p){vec2 i=floor(p);vec2 f=fract(p);f=f*f*(3.0-2.0*f);float a=hash(i);float b=hash(i+vec2(1.0,0.0));float c=hash(i+vec2(0.0,1.0));float d=hash(i+vec2(1.0,1.0));return mix(mix(a,b,f.x),mix(c,d,f.x),f.y);}
float fbm(vec2 p){float v=0.0;float a=0.5;for(int i=0;i<5;i++){v+=a*noise(p);p=p*2.03+vec2(13.1,7.7);a*=0.52;}return v;}
void main(){
 vec2 uv=vUv;
 vec2 p=(uv-0.5)*vec2(1.45,1.0)*uWashScale;
 float broad=fbm(p*1.35+vec2(0.0,uTime*0.006));
 float territorial=smoothstep(0.28,0.78,fbm(p*2.15+vec2(2.3,-1.7)));
 float feather=smoothstep(0.0,uTerritorySoftness,territorial);
 vec3 blue=vec3(0.13,0.25,0.54);
 vec3 cyan=vec3(0.31,0.72,0.82);
 vec3 violet=vec3(0.45,0.32,0.66);
 vec3 indigo=vec3(0.19,0.17,0.42);
 vec3 col=mix(blue,violet,0.35+0.35*broad*uVioletWeight);
 col=mix(col,cyan,0.18+0.34*feather*uCyanWeight);
 col=mix(col,indigo,0.14*smoothstep(0.62,0.96,fbm(p*4.4-1.6)));
 float paper=0.94+0.06*noise(uv*900.0)+uGrain*(noise(uv*220.0)-0.5);
 float pooled=smoothstep(0.74,0.98,fbm(p*3.2+4.0));
 col+=pooled*vec3(0.06,0.04,0.09);
 col*=paper;
 gl_FragColor=vec4(col,1.0);
}

