glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uTime;
uniform float uSeed;
uniform vec2 uStainCenter;
uniform float uStainRadius;
uniform float uLineWidth;
uniform float uCompression;
float hash(float n){return fract(sin(n+uSeed*23.7)*43758.5453123);}
float wobble(float a,float k){return sin(a*k+uSeed*1.7)*0.035+sin(a*(k*0.53)+2.1)*0.022;}
void main(){
 vec2 p=(vUv-0.5)*2.0;
 vec2 c=uStainCenter;
 vec2 q=p-c;
 q.y/=uCompression;
 float ang=atan(q.y,q.x);
 float r=length(q);
 float stainShape=uStainRadius*(1.0+wobble(ang,5.0)+0.04*sin(ang*9.0));
 float stain=1.0-smoothstep(stainShape*0.72,stainShape*1.08,r);
 float edge=smoothstep(stainShape*1.05,stainShape*0.72,r);
 float loops=0.0;
 for(int i=0;i<7;i++){
 float fi=float(i);
 float target=uStainRadius*(1.22+fi*0.145+wobble(ang+fi,3.0));
 float d=abs(r-target);
 float width=uLineWidth*(1.0+0.35*hash(fi));
 loops+=1.0-smoothstep(width,width*2.4,d);
 }
 loops=clamp(loops,0.0,1.0);
 float interiorResidue=0.22*(1.0-smoothstep(stainShape*0.15,stainShape*0.95,r));
 vec3 red=vec3(0.54,0.18,0.15);
 vec3 darkRed=vec3(0.32,0.08,0.08);
 vec3 gold=vec3(0.77,0.58,0.25);
 vec3 col=mix(darkRed,red,edge+interiorResidue);
 col=mix(col,gold,loops);
 float alpha=max(stain*0.78,loops*0.9);
 alpha*=1.0-smoothstep(0.95,1.35,length(p));
 gl_FragColor=vec4(col,alpha);
}

