glsl.fragment:
precision highp float;
varying vec2 vUv;
uniform float uTime;
uniform float uSeed;
uniform float uTrailCount;
uniform float uVerticalBias;
uniform float uResidueOpacity;
uniform vec2 uSourceCenter;
float hash(float n){return fract(sin(n*41.17+uSeed*5.31)*43758.5453);}
void main(){
 vec2 p=(vUv-0.5)*2.0;
 vec3 col=vec3(0.12,0.25,0.48);
 float alpha=0.0;
 for(int i=0;i<48;i++){
 float fi=float(i);
 if(fi>=uTrailCount) break;
 float startX=uSourceCenter.x+(hash(fi)-0.5)*0.62;
 float startY=uSourceCenter.y+0.20+hash(fi+9.0)*0.22;
 float len=0.18+hash(fi+3.0)*0.62;
 float wav=sin((p.y+fi)*8.0+uSeed)*0.018+sin((p.y-fi)*17.0)*0.006;
 float x=startX+wav*(0.45+hash(fi+4.0));
 float down=smoothstep(startY,startY-0.06,p.y)*(1.0-smoothstep(startY-len,startY-len-0.12,p.y));
 float line=1.0-smoothstep(0.004,0.018+hash(fi+2.0)*0.012,abs(p.x-x));
 float a=line*down*(0.12+0.32*hash(fi+6.0))*uResidueOpacity;
 alpha=max(alpha,a);
 vec3 stainCol=mix(vec3(0.25,0.54,0.64),vec3(0.47,0.30,0.58),hash(fi+11.0));
 stainCol=mix(stainCol,vec3(0.55,0.20,0.17),smoothstep(0.0,0.35,1.0-abs(startX-uSourceCenter.x)));
 col=mix(col,stainCol,a*2.0);
 }
 float dust=(fract(sin(dot(vUv*vec2(1200.0,900.0),vec2(12.9898,78.233))+uSeed)*43758.5453));
 alpha+=smoothstep(0.985,1.0,dust)*0.035;
 gl_FragColor=vec4(col,clamp(alpha,0.0,0.62));
}
